51	    output wire  [15:0]     p0_in,
52	    input  wire  [15:0]     p0_out,
53	    input  wire  [15:0]     p0_outen,
54	    input  wire  [15:0]     p0_altfunc,
55	
56	    output wire  [15:0]     p1_in,
57	    input  wire  [15:0]     p1_out,
58	    input  wire  [15:0]     p1_outen,
59	    input  wire  [15:0]     p1_altfunc,
60	
61	    // Processor debug interface
62	    output wire             i_trst_n,
63	    output wire             i_swditms,
64	    output wire             i_swclktck,
65	    output wire             i_tdi,
66	    input  wire             i_tdo,
67	    input  wire             i_tdoen_n,
68	    input  wire             i_swdo,
69	    input  wire             i_swdoen,
70	
