72	    inout  wire   [15:0]    P0,
73	    inout  wire   [15:0]    P1,
74	
75	    input  wire             nTRST, // Not needed if serial-wire debug is used
76	    input  wire             TDI,   // Not needed if serial-wire debug is used
77	    inout  wire             SWDIOTMS,
78	    input  wire             SWCLKTCK,
79	    output wire             TDO);   // Not needed if serial-wire debug is used
80	
81	  //-------------------------------------------
