83	  //-------------------------------------------
84	  wire      [15:0]     p0_out_mux;
85	  wire      [15:0]     p1_out_mux;
86	
87	  wire      [15:0]     p0_out_en_mux;
88	  wire      [15:0]     p1_out_en_mux;
89	
